module.render:
const color = args.color || 'var(--accent-color)';
const cols = Math.max(1, Math.min(6, parseInt(args.columns, 10) || 1));
const iconSize = { small: '1.2em', medium: '1.6em', large: '2.2em' }[String(args.iconsize || 'medium').toLowerCase()] || '1.6em';
const gap = (args.gap && String(args.gap).trim()) || '14px 20px';
const valign = String(args.valign || 'top').toLowerCase() === 'center' ? 'center' : 'flex-start';
const items = sections.map((s) => (s || '').trim()).filter(Boolean);
let html = `\n\n<div class="mdp-mod-iconlist" style="--il-color:${color}; --il-icon-size:${iconSize}; --il-valign:${valign}; grid-template-columns: repeat(${cols}, 1fr); gap: ${gap};">`;
items.forEach((it) => {
  // Split off a leading emoji / symbol cluster.
  const m = it.match(/^(\S+)\s+([\s\S]*)$/);
  const icon = m ? m[1] : '•';
  const body = m ? m[2] : it;
  html += `<div class="mdp-il-item"><div class="mdp-il-icon">${icon}</div><div class="mdp-il-text">\n\n${body}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
